/* ════════════════════════════════════════════════════════════════
   FIREBASE REALTIME DATABASE
   ════════════════════════════════════════════════════════════════ */
const FB = "https://projuktipunjo-apk-default-rtdb.asia-southeast1.firebasedatabase.app";
const fbGet    = async p => { try { const r=await fetch(`${FB}/${p}.json`); return await r.json(); } catch { return null; } };
const fbSet    = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"PUT",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbPush   = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbPatch  = async (p,d) => { try { const r=await fetch(`${FB}/${p}.json`,{method:"PATCH",headers:{"Content-Type":"application/json"},body:JSON.stringify(d)}); return await r.json(); } catch { return null; } };
const fbDelete = async p => { try { await fetch(`${FB}/${p}.json`,{method:"DELETE"}); return true; } catch { return false; } };

// ── Notification helper ──────────────────────────────────────────
const sendNotification = async (userId, {type, title, body, icon="🔔", color="#60a5fa"}) => {
  if(!userId) return;
  const safeUid = userId.replace(/[.#$[\]]/g,"_");
  await fbPush(`notifications/${safeUid}`, {
    type, title, body, icon, color,
    read: false,
    createdAt: Date.now(),
    date: new Date().toLocaleDateString("bn-BD")
  });
};

// ── Notify all real admins (for student/client actions) ──────────
const notifyAllAdmins = async ({type, title, body, icon="🔔", color="#f59e0b"}) => {
  try {
    const usersData = await fbGet("users");
    if(!usersData) return;
    const admins = Object.values(usersData).filter(u =>
      !u.isDemo && (u.role==="admin" || u.role==="chief_admin") && u.userId
    );
    await Promise.all(admins.map(a => sendNotification(a.userId, {type, title, body, icon, color})));
  } catch(e) { /* silent fail */ }
};

