function ServicesPage() {
  const sc = useResponsive(); const isMob = sc === "mobile";
  const [cat, setCat] = useState("all");
  const [search, setSearch] = useState("");
  const [expanded, setExpanded] = useState(null);
  const q = search.toLowerCase();

  const filtered = SERVICES_DATA.filter(s => {
    const matchCat = cat === "all" || s.cat === cat;
    const matchQ = !q || s.title.toLowerCase().includes(q) || s.desc.toLowerCase().includes(q) || s.details.some(d => d.toLowerCase().includes(q));
    return matchCat && matchQ;
  });

  return (
    <PageWrap>
      <SectionHeader eye="SERVICES" title="আমাদের সেবাসমূহ" sub="প্রযুক্তিপুঞ্জের সকল সার্ভিস — ১৬+ ধরনের ডিজিটাল সেবা" />

      {/* Search */}
      <input
        value={search} onChange={e => setSearch(e.target.value)}
        placeholder="🔍 সার্ভিস খুঁজুন…"
        style={{ marginBottom: 14, width: "100%", maxWidth: 400, background: "rgba(255,255,255,0.04)", border: `1px solid ${C.border}`, color: C.white, borderRadius: 9, padding: "9px 14px", fontFamily: "inherit", fontSize: "0.87rem", outline: "none", boxSizing: "border-box" }}
      />

      {/* Category Filter */}
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 20 }}>
        {SERVICE_CATS.map(c => {
          const active = cat === c.id;
          return (
            <button key={c.id} onClick={() => setCat(c.id)} style={{
              background: active ? `linear-gradient(135deg,${C.skyDeep},${C.sky})` : "rgba(255,255,255,0.04)",
              border: active ? "none" : `1px solid ${C.border}`,
              borderRadius: 8, padding: isMob ? "6px 10px" : "7px 13px",
              color: active ? "#fff" : C.silver,
              fontSize: isMob ? "0.72rem" : "0.8rem",
              fontWeight: active ? 700 : 500,
              cursor: "pointer", fontFamily: "inherit", whiteSpace: "nowrap",
            }}>{c.icon} {c.label}</button>
          );
        })}
      </div>

      {/* Count */}
      <div style={{ fontSize: "0.73rem", color: C.dim, marginBottom: 14, fontWeight: 600 }}>
        {filtered.length}টি সার্ভিস পাওয়া গেছে
      </div>

      {/* Services Grid */}
      <div style={{ display: "grid", gridTemplateColumns: isMob ? "1fr" : "repeat(auto-fill,minmax(290px,1fr))", gap: 14 }}>
        {filtered.map(s => {
          const isOpen = expanded === s.id;
          return (
            <div key={s.id} style={{
              background: C.card, border: `1px solid ${isOpen ? s.color + "60" : C.border}`,
              borderRadius: 14, overflow: "hidden", transition: "all 0.25s",
              boxShadow: isOpen ? `0 4px 24px ${s.color}18` : "none",
            }}>
              <div
                onClick={() => setExpanded(isOpen ? null : s.id)}
                style={{ padding: "18px 18px 14px", cursor: "pointer", display: "flex", gap: 14, alignItems: "flex-start" }}
              >
                <div style={{
                  width: 46, height: 46, borderRadius: 12, flexShrink: 0,
                  background: `linear-gradient(135deg,${s.color}25,${s.color}10)`,
                  border: `1px solid ${s.color}30`,
                  display: "flex", alignItems: "center", justifyContent: "center", fontSize: "1.3rem"
                }}>{s.icon}</div>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", gap: 8, marginBottom: 5 }}>
                    <span style={{ fontWeight: 700, fontSize: "0.9rem", color: C.white, lineHeight: 1.4 }}>{s.title}</span>
                    <span style={{ color: C.dim, fontSize: "0.85rem", flexShrink: 0 }}>{isOpen ? "▲" : "▼"}</span>
                  </div>
                  <span style={{
                    background: s.color + "18", border: `1px solid ${s.color}30`,
                    color: s.color, fontSize: "0.6rem", fontWeight: 700,
                    padding: "2px 8px", borderRadius: 20, letterSpacing: "0.5px"
                  }}>{s.badge}</span>
                  <p style={{ fontSize: "0.8rem", color: C.silver, lineHeight: 1.7, margin: "8px 0 0" }}>{s.desc}</p>
                </div>
              </div>

              {isOpen && (
                <div style={{ padding: "0 18px 18px", borderTop: `1px solid ${C.border}` }}>
                  <div style={{ fontSize: "0.7rem", color: s.color, fontWeight: 700, letterSpacing: "1px", margin: "14px 0 10px" }}>সেবার বিস্তারিত:</div>
                  <div style={{ display: "flex", flexDirection: "column", gap: 7 }}>
                    {s.details.map((d, i) => (
                      <div key={i} style={{ display: "flex", gap: 8, alignItems: "flex-start" }}>
                        <span style={{ color: s.color, flexShrink: 0, fontSize: "0.75rem", marginTop: 2 }}>✔</span>
                        <span style={{ fontSize: "0.82rem", color: C.silver, lineHeight: 1.6 }}>{d}</span>
                      </div>
                    ))}
                  </div>
                  <div style={{
                    marginTop: 16, padding: "10px 14px",
                    background: `${s.color}0a`, border: `1px solid ${s.color}20`,
                    borderRadius: 10, display: "flex", alignItems: "center", gap: 10
                  }}>
                    <span>📞</span>
                    <div>
                      <div style={{ fontSize: "0.72rem", color: C.dim, marginBottom: 1 }}>সার্ভিস নিতে যোগাযোগ করুন</div>
                      <div style={{ fontSize: "0.82rem", color: s.color, fontWeight: 700 }}>+8801612745977</div>
                    </div>
                  </div>
                </div>
              )}
            </div>
          );
        })}
      </div>

      {filtered.length === 0 && (
        <div style={{ padding: 40, textAlign: "center", color: C.dim }}>কোনো সার্ভিস পাওয়া যায়নি।</div>
      )}

      {/* Contact Banner */}
      <div style={{ marginTop: 28, padding: "20px 22px", background: `linear-gradient(135deg,rgba(77,166,255,0.08),rgba(139,92,246,0.08))`, border: `1px solid rgba(77,166,255,0.2)`, borderRadius: 14, display: "flex", flexWrap: "wrap", gap: 14, alignItems: "center", justifyContent: "space-between" }}>
        <div>
          <div style={{ fontWeight: 700, fontSize: "0.95rem", color: C.white, marginBottom: 8 }}>💡 আমাদের বিশেষত্ব</div>
          <div style={{ display: "flex", flexWrap: "wrap", gap: 7 }}>
            {["✔ দ্রুত ও নির্ভরযোগ্য সেবা","✔ অভিজ্ঞ টেকনিক্যাল সাপোর্ট","✔ শিক্ষার্থী ও গ্রাহক বান্ধব","✔ আজীবন সহায়তার প্রতিশ্রুতি"].map((t,i) => (
              <span key={i} style={{ fontSize: "0.75rem", color: C.silver, background: "rgba(255,255,255,0.04)", border: `1px solid ${C.border}`, borderRadius: 20, padding: "4px 10px" }}>{t}</span>
            ))}
          </div>
        </div>
        <div style={{ textAlign: isMob ? "left" : "right" }}>
          <div style={{ fontSize: "0.72rem", color: C.dim, marginBottom: 4 }}>📍 চন্দ্রগঞ্জ, লক্ষ্মীপুর</div>
          <div style={{ fontSize: "1rem", fontWeight: 800, color: C.sky }}>+8801612745977</div>
          <div style={{ fontSize: "0.68rem", color: C.dim }}>শনি–বৃহস্পতি: সকাল ৯টা–রাত ৯টা</div>
          <div style={{ fontSize: "0.68rem", color: C.dim }}>শুক্রবার: বিকাল ৩টা–রাত ৯টা</div>
        </div>
      </div>
    </PageWrap>
  );
}
