/* ════════════════════════════════════════════════════════════════
   EARN POINTS PAGE  🟢
   ════════════════════════════════════════════════════════════════ */
function EarnPointsPage({student, onSubmit}) {
  const [selSvc, setSelSvc] = useState(null);
  const [note, setNote]     = useState("");
  const [loading, setLoading] = useState(false);
  const [done, setDone]     = useState(false);
  const [err, setErr]       = useState("");
  const [filterCat, setFilterCat] = useState("সব");
  const sc = useResponsive(); const mob = sc==="mobile";
  const cats = ["সব", ...Array.from(new Set(EARN_SERVICES.map(s=>s.cat)))];
  const filtered = filterCat==="সব" ? EARN_SERVICES : EARN_SERVICES.filter(s=>s.cat===filterCat);
  const submit = async () => {
    if(!selSvc){ setErr("একটি সেবা বেছে নিন।"); return; }
    setLoading(true); setErr("");
    const req = {
      userId: student?.id||"", userName: student?.name||"",
      type: "earn", serviceId: selSvc.id, serviceName: selSvc.name,
      category: selSvc.cat, points: selSvc.points,
      pointsMax: selSvc.pointsMax||selSvc.points,
      note: note.trim(), status: "pending",
      createdAt: Date.now(), date: new Date().toISOString().split("T")[0],
    };
    const fbResult = await fbPush("pointRequests", req);
    const savedReq = {...req, _key: fbResult?.name||("tmp_"+Date.now())};
    // ── immediately add to global store so Admin sees it right away ──
    if(!window._ppAllReqs) window._ppAllReqs=[...DEMO_POINT_REQUESTS];
    window._ppAllReqs.unshift(savedReq);
    setTimeout(()=>{ window._ppPtReqDirty = true; }, 500);
    if(onSubmit) onSubmit(savedReq);
    // ── notify all admins ──
    await notifyAllAdmins({
      type:"new_point_request", icon:"🟢", color:"#4ade80",
      title:"নতুন Earn Point অনুরোধ!",
      body:`${req.userName||"একজন ব্যবহারকারী"} — ${req.serviceName} (+${req.points} pts) অনুমোদনের জন্য অপেক্ষায়।`
    });
    setLoading(false); setDone(true);
  };
  if(done) return (
    <PageWrap>
      <Card style={{textAlign:"center",padding:"40px 24px",maxWidth:460}}>
        <div style={{fontSize:"3rem",marginBottom:12}}>🟢</div>
        <div style={{fontSize:"1.2rem",fontWeight:800,color:C.green,marginBottom:8}}>অনুরোধ জমা হয়েছে!</div>
        <div style={{fontSize:"0.85rem",color:C.silver,marginBottom:6}}>সেবা: <strong style={{color:C.white}}>{selSvc?.name}</strong></div>
        <div style={{fontSize:"0.85rem",color:C.silver,marginBottom:16}}>
          প্রত্যাশিত পয়েন্ট: <strong style={{color:C.green}}>+{selSvc?.points}{selSvc?.pointsMax&&selSvc.pointsMax!==selSvc.points?` – +${selSvc.pointsMax}`:""}</strong>
        </div>
        <Badge label="PENDING ADMIN APPROVAL" color={C.amber}/>
        <div style={{marginTop:8,fontSize:"0.75rem",color:C.dim}}>Admin অনুমোদনের পর পয়েন্ট যোগ হবে।</div>
        <div style={{marginTop:20}}><Btn onClick={()=>{setDone(false);setSelSvc(null);setNote("");}} variant="ghost">আরেকটি অনুরোধ করুন</Btn></div>
      </Card>
    </PageWrap>
  );
  return (
    <PageWrap>
      <SectionHeader eye="EARN POINTS 🟢" title="পয়েন্ট অর্জন করুন" sub="সেবা নিলে পয়েন্ট পাবেন — Admin অনুমোদনের পর যোগ হবে"/>
      <div style={{background:`${C.green}10`,border:`1px solid ${C.green}25`,borderRadius:12,padding:"12px 16px",marginBottom:20,display:"flex",alignItems:"center",gap:12}}>
        <span style={{fontSize:"1.4rem"}}>💡</span>
        <div style={{fontSize:"0.82rem",color:C.silver}}><strong style={{color:C.green}}>10 Points = ৳1</strong> &nbsp;|&nbsp; সমস্ত অনুরোধ Admin অনুমোদনের পর কার্যকর হয়</div>
      </div>
      <div style={{display:"flex",gap:8,flexWrap:"wrap",marginBottom:18}}>
        {cats.map(c=>(
          <button key={c} onClick={()=>setFilterCat(c)} style={{background:filterCat===c?`linear-gradient(135deg,${C.skyDeep},${C.sky})`:"rgba(255,255,255,0.05)",border:`1px solid ${filterCat===c?C.sky+"60":C.border}`,color:filterCat===c?"#fff":C.silver,borderRadius:20,padding:"5px 14px",fontSize:"0.75rem",fontWeight:600,cursor:"pointer",fontFamily:"inherit"}}>{c}</button>
        ))}
      </div>
      <div style={{display:"grid",gridTemplateColumns:mob?"1fr 1fr":"repeat(auto-fill,minmax(200px,1fr))",gap:10,marginBottom:22}}>
        {filtered.map(svc=>{
          const sel=selSvc?.id===svc.id;
          return (
            <div key={svc.id} onClick={()=>{setSelSvc(svc);setErr("");}} style={{background:sel?`${C.green}12`:C.card,border:`1.5px solid ${sel?C.green+"55":C.border}`,borderRadius:12,padding:"14px 12px",cursor:"pointer",transition:"all 0.15s",position:"relative"}}>
              {sel&&<span style={{position:"absolute",top:8,right:8,background:C.green,color:"#fff",borderRadius:20,padding:"1px 7px",fontSize:"0.6rem",fontWeight:700}}>✓</span>}
              <div style={{fontSize:"1.4rem",marginBottom:6}}>{svc.icon}</div>
              <div style={{fontSize:"0.78rem",fontWeight:700,color:C.white,marginBottom:4,lineHeight:1.3}}>{svc.name}</div>
              <div style={{fontSize:"0.7rem",color:C.dim,marginBottom:6}}>{svc.cat}</div>
              <div style={{fontWeight:800,color:C.green,fontSize:"0.88rem"}}>+{svc.points.toLocaleString()}{svc.pointsMax&&svc.pointsMax!==svc.points?` – +${svc.pointsMax.toLocaleString()}`:""} pts</div>
              <div style={{fontSize:"0.63rem",color:C.dim}}>= ৳{(svc.points/POINTS_RATE).toLocaleString()}</div>
            </div>
          );
        })}
      </div>
      {selSvc&&(
        <Card glow style={{maxWidth:500,marginBottom:10}}>
          <div style={{fontWeight:700,color:C.green,marginBottom:10}}>✅ নির্বাচিত: {selSvc.name}</div>
          <div style={{fontSize:"0.82rem",color:C.silver,marginBottom:14}}>পাবেন: <strong style={{color:C.green}}>+{selSvc.points.toLocaleString()} পয়েন্ট</strong></div>
          <Inp label="বিশেষ নোট (ঐচ্ছিক)" value={note} onChange={e=>setNote(e.target.value)} placeholder="কোনো বিশেষ তথ্য থাকলে লিখুন"/>
          {err&&<div style={{background:`${C.red}10`,border:`1px solid ${C.red}25`,borderRadius:8,padding:"9px 13px",marginBottom:12,fontSize:"0.8rem",color:C.red}}>{err}</div>}
          <Btn onClick={submit} variant="success" style={{width:"100%"}} disabled={loading}>{loading?"জমা হচ্ছে...":"🟢 Earn Request পাঠান →"}</Btn>
        </Card>
      )}
    </PageWrap>
  );
}

